import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getReports } from "../../features/Report/reportIssueSlice";
import { format } from "date-fns";

const IssueList = () => {
  const dispatch = useDispatch();
  const user = JSON.parse(localStorage.getItem("user"));
  const { reports, isLoading, isError } = useSelector((state) => state.issue) || {};
  
  const [filterStatus, setFilterStatus] = useState("");

  useEffect(() => {
    if (user?._id) {
        dispatch(getReports(user._id));  // Fetch reports for logged-in user
    }
  }, [dispatch, user?._id]);

  if (isLoading) return <p className="text-center">Loading issues...</p>;
  if (isError) return <p className="text-center text-red-500">Error loading issues.</p>;

  const filteredReports = filterStatus
    ? reports.filter(report => report.status === filterStatus)
    : reports;

  return (
    <div className="container mx-auto p-4">
      <h3 className="mb-4 text-2xl font-bold">Your Reported Issues</h3>

      {/* Filter Dropdown */}
      <div className="mb-4">
        <label className="mr-2 font-medium">Filter by Status:</label>
        <select
          className="border p-2 rounded"
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
        >
          <option value="">All</option>
          <option value="open">Open</option>
          <option value="in_progress">In Progress</option>
          <option value="closed">Closed</option>
        </select>
      </div>

      {/* Issues Table */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse border">
          <thead>
            <tr className="bg-gray-100">
              <th className="border p-2">Title</th>
              <th className="border p-2">Issue Type</th>
              <th className="border p-2">Priority</th>
              <th className="border p-2">Status</th>
              <th className="border p-2">Admin Response</th>
              <th className="border p-2">Created At</th>
            </tr>
          </thead>
          <tbody>
            {filteredReports.length > 0 ? (
              filteredReports.map((report) => (
                <tr key={report._id} className="text-center">
                  <td className="border p-2">{report.title}</td>
                  <td className="border p-2">{report.issueType}</td>
                  <td className="border p-2 capitalize">{report.priority}</td>
                  <td className="border p-2 font-bold text-blue-600">{report.status}</td>
                  <td className="border p-2 text-gray-700">
                    {report.adminResponse ? report.adminResponse : "No response yet"}
                  </td>
                  <td className="border p-2 text-gray-600">
                    {format(new Date(report.createdAt), "yyyy-MM-dd HH:mm")}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6" className="border p-4 text-center">
                  No issues reported yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default IssueList;
